int start = 0;
int length = text.length();

while (start < length) {
    // Find the start of a word (skip leading spaces)
    while (start < length && Character.isWhitespace(text.charAt(start))) {
        result.append('_');
        start++;
    }
    if (start >= length) {
        break;
    }
    int end = start;
    // Find the end of the current word
    while (end < length && !Character.isWhitespace(text.charAt(end))) {
        end++;
    }
    // Append the word
    result.append(text.substring(start, end));
    start = end;
    if (start < length) {
        // There is a space after the word
        // Check how far the next non-space is
        int nextNonSpace = start;
        while (nextNonSpace < length && Character.isWhitespace(text.charAt(nextNonSpace))) {
            nextNonSpace++;
        }
        if (nextNonSpace < length && (nextNonSpace - end) > 2) {
            result.append('-');
        } else {
            result.append('_');
        }
    }
}

return result.toString();

